// 初始化处理器标识符
static inline void inithartid(unsigned long hartid)
{
  asm volatile("mv tp, %0" : : "r"(hartid & 0x1));
}

// 定义一个静态且易变的整型变量 started，用于标记系统是否已经初始化启动
volatile static int started = 0;

// 主函数，系统启动入口
void main(unsigned long hartid, unsigned long dtb_pa)
{
  // 初始化处理器标识符
  inithartid(hartid);

  if (hartid == 0)
  {
    // 如果当前处理器为引导处理器  主处理器
    consoleinit(); // 初始化系统控制台
    printfinit();  // 初始化 printf 函数的锁
    print_logo();  // 打印系统的 Logo 或欢迎信息
#ifdef DEBUG
    printf("hart %d enter main()...\n", hartid); // 打印调试信息
#endif
    kinit();        // 初始化内存管理
    kvminit();      // 为内核创建一个直接映射的页表。
    kvminithart();  // 切换硬件页表寄存器到内核的页表，并启用分页
    timerinit();    // 初始化定时器
    trapinithart(); // 安装内核陷阱向量，包括中断处理程序
    procinit();     // 初始化进程管理相关的数据结构

    plicinit();     // 初始化外部中断控制器（PLIC）
    plicinithart(); // 初始化外部中断控制器（PLIC）的处理器相关部分
#ifndef QEMU
    fpioa_pin_init(); // 如果非 QEMU 环境，初始化 FPIOA
    dmac_init();      // 如果非 QEMU 环境，初始化 DMAC
#endif
    disk_init();                 // 初始化磁盘管理模块
    binit();                     // 初始化缓冲区缓存
    fileinit();                  // 初始化文件表

    userinit();                  // 初始化第一个用户进程

    __INF("hart 0 init done\n"); // 打印初始化完成的信息

    // 向其他处理器发送中断请求
    for (int i = 1; i < NCPU; i++)
    {
      unsigned long mask = 1 << i;
      sbi_send_ipi(&mask);
    }
    __sync_synchronize(); // 同步内存，确保各个处理器都能看到最新的数据
    started = 1;          // 标记系统已经初始化启动完成
  }
  else
  {
    // 其他处理器
    while (started == 0) // 处理其他处理器的情况，需要等待引导处理器初始化完成后，进行后续初始化操作
      ;
    __sync_synchronize(); // 同步内存
#ifdef DEBUG
    printf("hart %d enter main()...\n", hartid); // 打印调试信息
#endif
    kvminithart();               // 启用分页机制
    trapinithart();              // 安装内核陷阱向量，包括中断处理程序
    plicinithart();              // 初始化外部中断控制器（PLIC）的处理器相关部分
    __INF("hart 1 init done\n"); // 打印初始化完成的信息
  }
  scheduler(); // 启动调度器，开始执行进程调度
}

