// 必须在中断禁用状态下调用，以防止进程被移动到不同的 CPU 时出现竞争情况
int cpuid()
{
  int id = r_tp();
  return id;
}

// 返回当前 CPU 对应的 cpu 结构
// 必须在中断禁用状态下调用
struct cpu *mycpu(void)
{
  int id = cpuid();
  struct cpu *c = &cpus[id];

  return c;
}

// 返回当前所在的进程结构指针，如果没有则返回 0
struct proc *myproc(void)
{
  push_off();
  struct cpu *c = mycpu();
  struct proc *p = c->proc;
  pop_off();
  return p;
}

// 为进程分配一个新的进程 ID
int allocpid()
{
  int pid;

  acquire(&pid_lock);
  pid = nextpid;
  nextpid = nextpid + 1;
  release(&pid_lock);

  return pid;
}

