// 返回与虚拟地址 va 对应的页表 pagetable 中 PTE 的地址。如果 alloc!=0，创建任何需要的页表页。
//
// risc-v Sv39 方案有三级页表，一个页表页包含 512 个 64 位的 PTE。
// 一个 64 位的虚拟地址被分为五个字段：
//   39..63 -- 必须为零。
//   30..38 -- 第二级索引的 9 位。
//   21..29 -- 第一级索引的 9 位。
//   12..20 -- 第零级索引的 9 位。
//    0..11 -- 页内字节偏移的 12 位。
pte_t *
walk(pagetable_t pagetable, uint64 va, int alloc)
{

  if(va >= MAXVA)
    panic("walk");

  for (int level = 2; level > 0; level--) // 从最高级到最低级（即从根表开始到最底层页表）遍历。循环的终止条件是 level > 0，因为 Sv39 方案有三级页表，其中第 0 级索引对应的是具体的物理页。
  {
    pte_t *pte = &pagetable[PX(level, va)]; // 根据当前虚拟地址 va 和当前级别 level 计算出对应的页表项的指针 pte
    if (*pte & PTE_V)                       // 检查该页表项是否有效（即 PTE 中的 PTE_V 标志位是否被设置）
    { // 如果该页表项有效，说明找到了对应的页表页，将当前页表指针更新为下一级页表的物理地址。
      pagetable = (pagetable_t)PTE2PA(*pte);
    }
    else // 如果无效，则根据参数 alloc 决定是否需要分配新的页表页
    {
      if(!alloc || (pagetable = (pde_t*)kalloc()) == NULL)
        return NULL;
      memset(pagetable, 0, PGSIZE);
      *pte = PA2PTE(pagetable) | PTE_V; // 更新当前页表项为指向新分配的页表页的地址，并设置有效位
    }
  }
  return &pagetable[PX(0, va)]; // 返回与给定虚拟地址对应的最底层页表项的地址 （因为在虚拟内存系统中，一个虚拟地址需要经过多级页表的映射才能找到对应的物理地址。因此，这个函数需要返回的是最底层页表项，因为它存储了最终的物理地址映射。）
}

// 查找虚拟地址，返回物理地址，如果没有映射则返回 0。
// 只能用于查找用户页面。
uint64
walkaddr(pagetable_t pagetable, uint64 va)
{
  pte_t *pte;
  uint64 pa;

  if(va >= MAXVA)
    return NULL;

  pte = walk(pagetable, va, 0); // 第三个参数 0 表示不进行分配，只是查找，不创建新的页表项
  if (pte == 0)                 // 如果返回的页表项指针为空，说明在给定的页表中没有找到对应的页表项，直接返回 0
    return NULL;
  if ((*pte & PTE_V) == 0) // 检查查找到的页表项是否有效
    return NULL;
  if ((*pte & PTE_U) == 0) // 检查查找到的页表项是否具有用户权限，如果没有用户权限，则返回 0。
    return NULL;
  pa = PTE2PA(*pte); // 如果页表项有效，通过 PTE2PA 宏将页表项转换为物理地址，并赋值给 pa。
  return pa;
}

// 向内核页表添加映射。
// 仅在启动时使用。
// 不会刷新 TLB 或启用分页。
void
kvmmap(uint64 va, uint64 pa, uint64 sz, int perm)
{
  if(mappages(kernel_pagetable, va, sz, pa, perm) != 0)
    panic("kvmmap");
}

// 将内核虚拟地址转换为物理地址。
// 仅需用于栈上的地址。
// 假设 va 是页面对齐的。
uint64
kvmpa(uint64 va)
{
  return kwalkaddr(kernel_pagetable, va);
}

uint64
kwalkaddr(pagetable_t kpt, uint64 va)
{
  uint64 off = va % PGSIZE;
  pte_t *pte;
  uint64 pa;

  pte = walk(kpt, va, 0);
  if(pte == 0)
    panic("kvmpa");
  if((*pte & PTE_V) == 0)
    panic("kvmpa");
  pa = PTE2PA(*pte);
  return pa+off;   // 这个va不仅仅是页帧的首地址，因此需要加上偏移量
}

// 实现虚拟地址到物理地址的映射----函数参数：页表 pagetable、虚拟地址 va、大小 size、物理地址 pa 和权限 perm
// 为从 va 开始的虚拟地址创建指向从 pa 开始的物理地址的 PTE。
// va 和 size 可能不是页面对齐的。成功返回 0，如果 walk() 无法分配所需的页表页，返回 -1。
int
mappages(pagetable_t pagetable, uint64 va, uint64 size, uint64 pa, int perm)
{
  uint64 a, last; // 保存起始和结束的虚拟地址
  pte_t *pte;     // 指向页表项

  a = PGROUNDDOWN(va); // 将虚拟地址 va 向下舍入到页面边界
  last = PGROUNDDOWN(va + size - 1);

  for(;;){
    if ((pte = walk(pagetable, a, 1)) == NULL) // 调用 walk 函数，尝试找到给定虚拟地址对应的页表项，如果找不到或无法分配所需的页表页，则返回 -1。
      return -1;
    if (*pte & PTE_V) // 检查页表项是否已经被映射（即是否已经被设置为有效），如果是，则发生错误（panic），因为这意味着重复映射
      panic("remap");
    *pte = PA2PTE(pa) | perm | PTE_V; // 将页表项设置为指向物理地址 pa 的指针，并设置权限 perm，并将有效位 PTE_V 设置为 1，表示这个映射是有效的。
    if (a == last)                    // 如果当前虚拟地址已经是结束地址，退出循环
      break;
    a += PGSIZE; // 更新虚拟地址和物理地址，准备处理下一页（因为是以页为单位，因此只有设置好了页的起始地址，那么直接开始下一页）
    pa += PGSIZE;
  }
  return 0;
}
//不用页对齐的映射
