{
  uint64 a, last; // 保存起始和结束的虚拟地址
  pte_t *pte;     // 指向页表项

  a = va; // 不强制对齐到页面边界
  last = va + size - 1;

  for (;;)
  {
    if ((pte = walk(pagetable, a, 1)) == NULL) // 调用 walk 函数，尝试找到给定虚拟地址对应的页表项，如果找不到或无法分配所需的页表页，则返回 -1。
      return -1;
    // if (*pte & PTE_V) // 检查页表项是否已经被映射（即是否已经被设置为有效），如果是，则发生错误（panic），因为这意味着重复映射
    //   panic("remap");
    *pte = PA2PTE(pa) | perm | PTE_V; // 将页表项设置为指向物理地址 pa 的指针，并设置权限 perm，并将有效位 PTE_V 设置为 1，表示这个映射是有效的。
    if (a == last)                    // 如果当前虚拟地址已经是结束地址，退出循环
      break;
    a += PGSIZE; // 更新虚拟地址和物理地址，准备处理下一页（因为是以页为单位，因此只有设置好了页的起始地址，那么直接开始下一页）
    pa += PGSIZE;
  }
  return 0;
}

// 从 va 开始移除 npages 的映射。va 必须是页面对齐的。映射必须存在。
// 可选释放物理内存。
void
vmunmap(pagetable_t pagetable, uint64 va, uint64 npages, int do_free)
{
  uint64 a;
  pte_t *pte;

  if((va % PGSIZE) != 0)
    panic("vmunmap: not aligned");

  for(a = va; a < va + npages*PGSIZE; a += PGSIZE){
    if((pte = walk(pagetable, a, 0)) == 0)
      continue;
    if((*pte & PTE_V) == 0)
      continue;
    if(PTE_FLAGS(*pte) == PTE_V)
      panic("vmunmap: not a leaf");
    if(do_free){
      if((*pte&PTE_R)!=0){
        uint64 pa = PTE2PA(*pte);
        kfree((void*)pa); 
      }
    }
    *pte = 0;
  }
}

// 创建一个空的用户页表。
// 如果内存不足，返回 0。
pagetable_t
uvmcreate()
{
  pagetable_t pagetable;
  pagetable = (pagetable_t) kalloc();
  if(pagetable == NULL)
    return NULL;
  memset(pagetable, 0, PGSIZE);
  return pagetable;
}

