// Physical memory allocator, for user processes, kernel stacks, page-table pages, and pipe buffers. Allocates whole 4096-byte pages.

#include "include/types.h"
#include "include/param.h"
#include "include/memlayout.h"
#include "include/riscv.h"
#include "include/spinlock.h"
#include "include/kalloc.h"
#include "include/string.h"
#include "include/printf.h"

void freerange(void *pa_start, void *pa_end);  // 函数声明
char *mm_table;  // 内存管理表的指针
int mm_table_sz=0;  // 内存管理表的大小
uint64 pa_addr_start=0;  // 物理地址的起始位置

extern char kernel_end[];  // 内核结束位置的符号
struct run {
  struct run *next;  // 下一个空闲页的指针
};

struct {
  struct spinlock lock;  // 自旋锁
  struct run *freelist;  // 空闲页链表的头指针
  uint64 npage;  // 空闲页面数量
} kmem;  // 内核内存结构体

extern char etext[];  // 代码段结束位置的符号

// 初始化内存管理
void kinit() {
  initlock(&kmem.lock, "kmem");  // 初始化内核内存锁
  printf("-----------kernel_end-------%p\n", (uint64)kernel_end); // 打印内核结束位置  （内核中在内存中不仅包括代码段，还包括数据段、BSS 段以及其他可能的内核模块。因此比代码段的结束位置大）
  printf("-----------etext------------%p\n",(uint64)etext);  // 打印代码段结束位置
  kmem.freelist = 0;  // 空闲页链表初始化为空
  kmem.npage = 0;  // 空闲页面数量初始化为0
  freerange(kernel_end, (void*)PHYSTOP);  // 释放内存区域  从内核结束的位置开始
}

// 释放给定范围内的物理内存
void freerange(void *pa_start, void *pa_end) {
  char *p;  // 指针
  p = (char*)PGROUNDUP((uint64)pa_start);  // 向上对齐到页边界（将地址转换成页边界，因为后面都是根据页边距来操作页帧）
  mm_table_sz = ((uint64)pa_end - (uint64)p) / PGSIZE;        // 计算内存管理表的大小 即 pa_start 到 pa_end 之间的页数。
  int mm_table_page_sz = (mm_table_sz + PGSIZE - 1) / PGSIZE; // 计算内存管理表占用的页数
  mm_table_sz -= mm_table_page_sz;                            // 实际内存管理表的大小  可以使用的总页数 - 内存管理表占用的页数

  mm_table = p;                   // 内存管理表的起始位置将指针
  p += mm_table_page_sz * PGSIZE; // 将指针 p 移动到内存管理表之后

  pa_addr_start = (uint64)p;                      // 物理地址的起始位置  去掉内存管理表占用的内存之后的物理地址
  for(; p + PGSIZE < (char*)pa_end; p += PGSIZE)  // 遍历要释放的内存区域
    kfree(p);  // 释放每一页内存
  memset(mm_table, 0, mm_table_sz);  // 清空内存管理表
}

// 释放给定的物理页
void kfree(void *pa) {
  struct run *r;  // 空闲页指针

  if(((uint64)pa % PGSIZE) != 0 || (char*)pa < kernel_end || (uint64)pa >= PHYSTOP)  // 判断物理地址是否合法
    panic("panic in kfree");  // 不合法则触发内核恐慌

  int index=((uint64)pa-pa_addr_start)/PGSIZE;  // 计算页的索引
  if(mm_table[index]>1)
  {                     // 如果引用计数大于1  说明该页还在被多个引用使用，只需减少引用计数并返回，而不释放实际内存。
    --mm_table[index];  // 减小引用计数
    return;  // 退出函数
  }
  // 用无效数据填充以捕获悬空引用
  memset(pa, 1, PGSIZE);  // 用垃圾值填充内存

  r = (struct run*)pa;  // 转换为空闲页结构体指针

  // 加入空闲页链表
  acquire(&kmem.lock);  // 获取内核内存锁
  r->next = kmem.freelist; // 将当前页的 next 指针指向空闲页链表的头部
  kmem.freelist = r;       // 将空闲页链表的头指针更新为当前页
  kmem.npage++;  // 空闲页面数量加1
  --mm_table[index];  // 减小引用计数
  release(&kmem.lock);  // 释放内核内存锁
}

// 分配一页物理内存
void *kalloc(void) {
  struct run *r;  // 空闲页指针

  acquire(&kmem.lock);  // 获取内核内存锁
  r = kmem.freelist;  // 获取空闲页链表中的第一个页

  if (r)              // 若存在空闲页
  {                           
    kmem.freelist = r->next;  // 更新空闲页链表的头指针
    kmem.npage--;  // 空闲页面数量减1
  }
  int index=((uint64)r-pa_addr_start)/PGSIZE;  // 计算页的索引
  ++mm_table[index];  // 增加引用计数
  release(&kmem.lock);  // 释放内核内存锁

  if(r)
    memset((char*)r, 5, PGSIZE); // 填充内存为垃圾值
  return (void*)r;  // 返回分配的物理页的地址
}

// 返回当前可用的内存大小
uint64 freemem_amount(void) {
  return kmem.npage << PGSHIFT;  // 返回空闲页面数量 * 4096 也就是左移12位 
}

// 分配两页物理内存
void *kalloc_two_pages(void)
{
  struct run *r1, *r2; // 空闲页指针

  acquire(&kmem.lock); // 获取内核内存锁

  // 分配第一个页帧
  r1 = kmem.freelist; // 获取空闲页链表中的第一个页
  if (r1)
  {
    kmem.freelist = r1->next; // 更新空闲页链表的头指针
    kmem.npage--;             // 空闲页面数量减1
  }

  // 分配第二个页帧
  r2 = kmem.freelist; // 获取空闲页链表中的第一个页
  if (r2)
  {
    kmem.freelist = r2->next; // 更新空闲页链表的头指针
    kmem.npage--;             // 空闲页面数量减1
  }

  // 计算两个页的索引
  int index1 = ((uint64)r1 - pa_addr_start) / PGSIZE;
  int index2 = ((uint64)r2 - pa_addr_start) / PGSIZE;

  // 增加引用计数
  ++mm_table[index1];
  ++mm_table[index2];

  release(&kmem.lock); // 释放内核内存锁

  // 返回两个页帧的开头
  if (r1 && r2)
    return (void *)r1;
  else
    return NULL; // 如果有一个分配失败，则返回 NULL
}

