// 初始化异常和中断处理
void
trapinithart(void)
{
  w_stvec((uint64)kernelvec); // 设置内核中断处理入口地址
  w_sstatus(r_sstatus() | SSTATUS_SIE); // 开启内核模式下的中断使能
  // 开启监督者模式下的定时器中断
  w_sie(r_sie() | SIE_SEIE | SIE_SSIE | SIE_STIE);
  set_next_timeout(); // 设置下一个超时
  #ifdef DEBUG
  printf("trapinithart\n");
  #endif
}

// 处理来自用户空间的中断、异常或系统调用
void
usertrap(void)
{
  int which_dev = 0;

  if((r_sstatus() & SSTATUS_SPP) != 0)
    panic("usertrap: not from user mode"); // 抛出异常

  // 将中断和异常重定向到kerneltrap()，因为现在在内核中
  w_stvec((uint64)kernelvec);

  struct proc *p = myproc();

  // 保存用户程序计数器
  p->trapframe->epc = r_sepc();

  if(r_scause() == 8){
    // 系统调用
    if(p->killed)
      exit(-1);
    // sepc指向ecall指令，但我们希望返回到下一条指令
    p->trapframe->epc += 4;
    // 中断将改变sstatus等寄存器，因此在处理完这些寄存器之前不要启用中断
    intr_on();
    syscall();
  } 
  else if((which_dev = devintr(0)) != 0){
    // 设备中断
  } 
  else if(page_fault()!=0){
    // 页面错误
  }
  else {
    printf("\nusertrap(): unexpected scause %p pid=%d %s\n", r_scause(), p->pid, p->name);
    printf("            sepc=%p stval=%p\n", r_sepc(), r_stval());
    // trapframedump(p->trapframe);
    p->killed = 1;
  }

  if(p->killed)
    exit(-1);

  // 如果是定时器中断，放弃CPU
  if(which_dev == 2){
    p->slot--;
    if (p->slot == 0){
      p->slot = 1;
      yield();
    }

  }


  usertrapret();
}

// 返回到用户空间
void
usertrapret(void)
{
  struct proc *p = myproc();

  // 即将在trampoline.S中切换中断处理的目标，所以在回到用户空间之前关闭中断
  intr_off();

  // 将系统调用、中断和异常重定向到trampoline.S
  w_stvec(TRAMPOLINE + (uservec - trampoline));

  // 设置trampoline.S在进程下一次重新进入内核时需要的trapframe值
  p->trapframe->kernel_satp = r_satp(); // 内核页表
  p->trapframe->kernel_sp = p->kstack + PGSIZE; // 进程的内核栈
  p->trapframe->kernel_trap = (uint64)usertrap;
  p->trapframe->kernel_hartid = r_tp(); // cpuid()的hartid

  // 设置sret将用到的寄存器，以返回到用户空间
  unsigned long x = r_sstatus();
  x &= ~SSTATUS_SPP; // 清除SPP以便用户模式
  x |= SSTATUS_SPIE; // 在用户模式下启用中断
  w_sstatus(x);

  // 设置S异常程序计数器为保存的用户pc
  w_sepc(p->trapframe->epc);

  // 告诉trampoline.S切换到的用户页表
  uint64 satp = MAKE_SATP(p->pagetable);

  // 跳转到trampoline.S在内存顶部的位置，该位置将切换到用户页表、恢复用户寄存器，并用sret切换到用户模式
  uint64 fn = TRAMPOLINE + (userret - trampoline);
  ((void (*)(uint64,uint64))fn)(TRAPFRAME, satp);
}

// 内核代码段的中断和异常都会经过kernelvec()函数
// 在当前内核栈上
void 
kerneltrap() {

  int which_dev = 0;
  uint64 sepc = r_sepc();
  uint64 sstatus = r_sstatus();
  uint64 scause = r_scause();

  if((sstatus & SSTATUS_SPP) == 0)
    panic("kerneltrap: not from supervisor mode"); // 抛出异常
  if(intr_get() != 0)
    panic("kerneltrap: interrupts enabled"); // 抛出异常

  if((which_dev = devintr(1)) == 0){
    printf("----------------------%p\n",r_stval());
    printf("\nscause %p\n", scause);
    printf("sepc=%p stval=%p hart=%d\n", r_sepc(), r_stval(), r_tp());
    struct proc *p = myproc();
    if (p != 0) {
      printf("pid: %d, name: %s\n", p->pid, p->name);
    }
    panic("kerneltrap");
  }

  // 如果是定时器中断，放弃CPU
  if(which_dev == 2 && myproc() != 0 && myproc()->state == RUNNING) {
    struct proc *p = myproc();
    p->slot--;
    if (p->slot == 0)
    {
      p->slot = 1;
      yield();
    }
  }
  // yield()可能导致一些中断发生，所以恢复用于trampoline.S的中断寄存器
  w_sepc(sepc);
  w_sstatus(sstatus);
}

// 检查是否是外部/软件中断，并进行处理
// 返回2表示定时器中断，1表示其他设备中断，0表示未识别
int devintr(int cpl) {
	uint64 scause = r_scause();

	#ifdef QEMU 
	// 处理外部中断
	if ((0x8000000000000000L & scause) && 9 == (scause & 0xff)) 
	#else 
	// 在k210上，替代外部中断是监督者软件中断
	// 它是监督者外部中断在k210上不可用的另一种选择
	if (0x8000000000000001L == scause && 9 == r_stval()) 
	#endif 
	{
		int irq = plic_claim();
		if (UART_IRQ == irq) {
			// 键盘输入
			int c = sbi_console_getchar();
			if (-1 != c) {
				consoleintr(c);
			}
		}
		else if (DISK_IRQ == irq) {
			disk_intr();
		}
		else if (irq) {
			printf("unexpected interrupt irq = %d\n", irq);
		}

		if (irq) { plic_complete(irq);}

		#ifndef QEMU 
		w_sip(r_sip() & ~2);    // 清除挂起位
		sbi_set_mie();
		#endif 

		return 1;
	}
	else if (0x8000000000000005L == scause) {
		timer_tick(cpl);
		return 2;
	}
	else { return 0;}
}

// 处理存储故障（写操作引发的页缺失）
// addr: 发生故障的虚拟地址
int do_store_fault(uint64 addr){
  //printf("------%s-----store %d\n",myproc()->name,addr);
  pte_t *pte,*kpte;
  uint64 pa;
  char *mem;
  uint flags;
  struct proc* p=myproc();
  if(addr>p->sz){
    panic("do_store_fault error");
  }
  addr=PGROUNDDOWN(addr);
  // 在进程页表中查找地址对应的页表项
  if((pte = walk(p->pagetable, addr, 0)) == NULL)
    panic("do_store_fault: pte should exist");

  // 检查页表项是否存在
  if((*pte&PTE_R)==0){
    //printf("------%s-----store %d\n",myproc()->name,addr);
    // 如果页表项不存在，分配一个新页面
    if((mem = kalloc()) == NULL)
      panic("no page");
    memset(mem, 0, PGSIZE);
    // 设置页表项标志
    *pte=PA2PTE((uint64)mem)|PTE_R|PTE_W|PTE_X|PTE_U|PTE_V;

    // 更新内核页表
    if((kpte = walk(p->kpagetable, addr, 0)) == NULL)
      panic("do_store_fault: kpte should exist");
    *kpte=*pte& ~PTE_U;
  }
  else{
    // 如果页已存在，则复制该页内容到内存中
    flags = PTE_FLAGS(*pte);
    pa = PTE2PA(*pte);
    if((mem = kalloc()) == NULL)
      panic("no page");
    memmove(mem, (char*)pa, PGSIZE);
    *pte=PA2PTE((uint64)mem)|flags|PTE_W;
    kfree((void *)pa);

    // 更新内核页表
    if((kpte = walk(p->kpagetable, addr, 0)) == NULL)
      panic("do_store_fault: kpte should exist");
    *kpte=*pte& ~PTE_U;
  }

  return 1;
}

// 处理加载故障（读操作引发的页缺失）
int do_load_fault(uint64 addr){
  pte_t *pte,*kpte;
  char *mem;
  //printf("load %d\n",addr);
  struct proc* p=myproc();
  //printf("load %d\n",p->sz);
  if(addr>p->sz){
    panic("do_load_fault error");
  }
  addr=PGROUNDDOWN(addr);
  // 在进程页表中查找地址对应的页表项
  if((pte = walk(p->pagetable, addr, 0)) == NULL)
    panic("do_load_fault: pte should exist");

  if(*pte&PTE_V){
    //printf("------%s-----load %d\n",myproc()->name,addr);
    if((mem = kalloc()) == NULL)
      panic("no page");
    memset(mem, 0, PGSIZE);
    *pte=PA2PTE((uint64)mem)|PTE_R|PTE_W|PTE_X|PTE_U|PTE_V;

    // 更新内核页表
    if((kpte = walk(p->kpagetable, addr, 0)) == NULL)
      panic("do_store_fault: kpte should exist");
    *kpte=*pte& ~PTE_U;
  }

  return 1;
}

// 处理指令故障（执行指令引发的页缺失）
int do_ins_fault(uint64 addr){

  struct proc* p=myproc();
  printf("%s-----ins %p\n",p->name,addr);
  if(addr>p->sz){
    panic("do_store_fault error");
  }
  struct elf_seg my;
  // 获取进程初始加载段的基地址
  uint64 phaddr=p->my_seg.baseaddr;
  for(int j=0;j<p->my_seg.num;++j){
    //printf("----%d\n",phaddr);
    // 从进程的加载段读取elf_seg数据
    if(copy_elfseg(p->pagetable, phaddr,(char *)&my, sizeof(struct elf_seg)) < 0){
      panic("ins fault");
    }
    //printf("----%d\n",my.filesz);
    //printf("----%d\n",my.memsz);
    //printf("----%d\n",my.off);
    //printf("----%d\n",my.vaddr);
    // 判断地址是否在加载段的虚拟地址范围内
    if(addr>=my.vaddr&&addr<my.vaddr+my.filesz){
      uint64 tmp_addr=PGROUNDDOWN(addr);
      uint msz=PGROUNDDOWN(addr+PGSIZE)<my.vaddr+my.filesz?PGSIZE:my.vaddr+my.filesz-tmp_addr;
      // 在进程的页表和内核页表中分配内存
      if(uvmalloc(p->pagetable, p->kpagetable, tmp_addr, tmp_addr+PGSIZE) == 0){
        panic("ins fault");
      }
      // 检查加载地址是否对齐到页边界
      if(my.vaddr % PGSIZE != 0){
        panic("ins fault");
      }
      // 加载段到内存中
      if(loadseg(p->pagetable, tmp_addr, p->myep, my.off+(tmp_addr-my.vaddr),msz) < 0){
        panic("ins fault");
      }
      return 1;
    }
    phaddr+=sizeof(struct elf_seg);
  }
  return -1;
}


