  struct proc *p = myproc();
  if(addr >= p->sz || addr+sizeof(uint64) > p->sz)
    return -1;
  // if(copyin(p->pagetable, (char *)ip, addr, sizeof(*ip)) != 0)
  if(copyin2((char *)ip, addr, sizeof(*ip)) != 0)
    return -1;
  return 0;
}

// 从当前进程中获取地址addr处的以空字符结尾的字符串。
// 返回字符串的长度（不包括空字符），如果出错返回-1。
int
fetchstr(uint64 addr, char *buf, int max)
{
  // struct proc *p = myproc();
  // int err = copyinstr(p->pagetable, buf, addr, max);
  int err = copyinstr2(buf, addr, max);
  if(err < 0)
    return err;
  return strlen(buf);
}

static uint64
argraw(int n)
{
  struct proc *p = myproc();
  switch (n) {
  case 0:
    return p->trapframe->a0;
  case 1:
    return p->trapframe->a1;
  case 2:
    return p->trapframe->a2;
  case 3:
    return p->trapframe->a3;
  case 4:
    return p->trapframe->a4;
  case 5:
    return p->trapframe->a5;
  }
  panic("argraw");
  return -1;
}

// 从第n个32位系统调用参数中获取整数值。
int
argint(int n, int *ip)
{
  *ip = argraw(n);
  return 0;
}

// 以指针形式检索参数。
// 由于copyin/copyout将执行检查，因此这里不再检查合法性。
int
argaddr(int n, uint64 *ip)
{
  *ip = argraw(n);
  return 0;
}

// 从第n个字大小的系统调用参数中获取一个以空字符结尾的字符串。
// 最多复制max个字符进入buf。
// 如果成功，返回字符串长度（包括结尾的空字符），如果出错，返回-1。
int
argstr(int n, char *buf, int max)
{
  uint64 addr;
  if(argaddr(n, &addr) < 0)  // 获取第n个参数的地址
    return -1;
  return fetchstr(addr, buf, max);  // 复制字符串到buf，最多max个字符
}

