void
syscall(void) 
{
  int num;
  struct proc *p = myproc();

  num = p->trapframe->a7;
  if(num > 0 && num < NELEM(syscalls) && syscalls[num]) {
    // if(num!=64){
    //   printf("%s----->sp----%d\n",p->name,p->trapframe->sp);
    // }
    p->trapframe->a0 = syscalls[num]();   // 这个代码是执行系统调用号对应的函数，并且将结果返回到a0寄存器
        // trace  检查当前进程是否设置了掩码，如果设置了那么就进行跟踪打印
    if ((p->tmask & (1 << num)) != 0) {
      printf("pid %d: %s -> %d\n", p->pid, sysnames[num], p->trapframe->a0);
    }
  } else {
    printf("pid %d %s: unknown sys c all %d\n",
            p->pid, p->name, num);
    p->trapframe->a0 = -1;
  }
}

