  return kill(pid);
}

// return how many clock tick interrupts have occurred
// since start.
uint64
sys_uptime(void)
{
  uint xticks;

  acquire(&tickslock);
  xticks = ticks;
  release(&tickslock);
  return xticks;
}

uint64
sys_times(void)
{
  struct proc *p = myproc();
  uint64 addr_tms;
  int xticks;
  if (argaddr(0, &addr_tms) < 0)
  {
    return -1;
  }
  struct tms *t = (struct tms *)addr_tms;

  if (t != 0)
  {
    t->tms_cstime = p->ti.tms_cstime;
    t->tms_cutime = p->ti.tms_cutime;
    t->tms_stime = p->ti.tms_stime;
    t->tms_utime = p->ti.tms_utime;
  }
  // printf("ddd");
  acquire(&tickslock);
  xticks = (int)(ticks / INTERVAL);
  release(&tickslock);
  // printf("+++++++++++++%d\n",xticks);
  return xticks;
}

