//
// File-system system calls.
// Mostly argument checking, since we don't trust
// user code, and calls into file.c and fs.c.
//

#include "include/types.h"
#include "include/riscv.h"
#include "include/param.h"
#include "include/stat.h"
#include "include/spinlock.h"
#include "include/proc.h"
#include "include/sleeplock.h"
#include "include/file.h"
#include "include/pipe.h"
#include "include/fcntl.h"
#include "include/fat32.h"
#include "include/syscall.h"
#include "include/string.h"
#include "include/printf.h"
#include "include/vm.h"
#include "include/uname.h"
#include "include/timer.h"

// Fetch the nth word-sized system call argument as a file descriptor
// and return both the descriptor and the corresponding struct file.
// 读取文件描述符和对应文件
static int
argfd(int n, int *pfd, struct file **pf)
{
  int fd;
  struct file *f;

  if (argint(n, &fd) < 0)
    return -1;
  if (fd < 0 || fd >= NOFILE || (f = myproc()->ofile[fd]) == NULL)
    return -1;
  if (pfd)
    *pfd = fd;
  if (pf)
    *pf = f;
  return 0;
}

// Allocate a file descriptor for the given file.
// Takes over file reference from caller on success.
// 分配文件描述符
static int
fdalloc(struct file *f)
{
  int fd;
  struct proc *p = myproc();

  for (fd = 0; fd < NOFILE; fd++)
  {
    if (p->ofile[fd] == 0)
    {
      p->ofile[fd] = f;
      return fd;
    }
  }
  return -1;
}

// 复制文件描述符
uint64
sys_dup(void)
{
  struct file *f; // 声明文件指针变量f
  int fd;         // 声明文件描述符变量fd

  // 通过系统调用获取文件指针
  if (argfd(0, 0, &f) < 0)
  {
    printf("read register failed\n"); // 如果获取文件句柄失败，打印错误信息
    return -1;                        // 返回-1表示出错
  }
  // 通过系统调用分配新的文件描述符
  if ((fd = fdalloc(f)) < 0)
  {
    printf("fdalloc failed"); // 如果分配文件描述符失败，打印错误信息
    return -1;                // 返回-1表示出错
  }
  // 复制文件指针f，增加文件引用计数
  filedup(f);
  // 返回新分配的文件描述符
  return fd;
}

// 通过系统调用复制文件描述符，并将其关联到一个新的文件描述符上。
uint64
sys_dup3(void)
{
  struct file *f1; // 声明文件指针变量f1，用于存储原始文件对象
  struct file *f2; // 声明文件指针变量f2，用于存储新文件描述符关联的之前的文件对象
  int oldfd;       // 声明整型变量oldfd，用于存储原始文件描述符
  int newfd;       // 声明整型变量newfd，用于存储新文件描述符

  // 获取原始文件描述符和原始文件对象
  if (argfd(0, &oldfd, &f1) < 0)
    return -1;

  // 获取新的文件描述符
  if (argint(1, &newfd) < 0)
    return -1;

  // 如果新旧文件描述符相同，直接返回新的文件描述符
  if (newfd == oldfd)
    return newfd;

  // 检查新的文件描述符是否有效
  if (newfd < 0 || newfd >= NOFILE)
    return -1;

  // 如果新的文件描述符之前已经被打开过
  if (myproc()->ofile[newfd])
  {
    f2 = myproc()->ofile[newfd]; // 存储之前关联的文件对象
    myproc()->ofile[newfd] = 0;  // 将文件表中对应的文件指针置为NULL
    fileclose(f2);               // 关闭之前关联的文件对象
  }

  myproc()->ofile[newfd] = f1; // 将新的文件描述符与原始文件对象关联
  filedup(f1);                 // 增加原始文件对象的引用计数
  return newfd;                // 返回新的文件描述符
}

// 读文件系统调用函数
uint64
sys_read(void)
{
  // printf("reading\n");  // 可选的调试打印语句
  struct file *f; // 文件指针
  int count;      // 读取数据的字节数
  uint64 buf;     // 目标缓冲区的地址

  // 从系统调用参数中获取文件指针、读取数据的字节数和目标缓冲区的地址，并进行有效性检查
  if (argfd(0, 0, &f) < 0 || argint(2, &count) < 0 || argaddr(1, &buf) < 0)
    return -1; // 参数无效时返回 -1

  // 调用 fileread 函数执行文件读取操作，并返回读取的结果
  return fileread(f, buf, count);
}

// 写文件
uint64 
sys_write(void)
{
  // printf("writint\n"); 
