// 创建文件
static struct dirent *create(char *path, short type, int mode)
{
  struct dirent *ep, *dp;          // 文件目录项指针
  char name[FAT32_MAX_FILENAME + 1];  // 文件名字符串

  // 获取文件的父文件目录项
  if ((dp = enameparent(path, name)) == NULL)
    return NULL;  // 获取失败时返回 NULL

  // 根据文件类型设置权限模式
  if (type == T_DIR)
  {
    mode = ATTR_DIRECTORY;
  }
  else if (mode & O_RDONLY)
  {
    mode = ATTR_READ_ONLY;
  }
  else
  {
    mode = 0;
  }

  elock(dp);  // 锁定父目录项

  // 在父目录项中分配并创建新的目录项
  if ((ep = ealloc(dp, name, mode)) == NULL)
  {
    eunlock(dp);  // 在创建失败时释放父目录项的锁
    eput(dp);     // 并释放父目录项的内存
    return NULL;  // 创建失败时返回 NULL
  }

  // 检查文件类型是否与目标类型匹配
  if ((type == T_DIR && !(ep->attribute & ATTR_DIRECTORY)) ||
      (type == T_FILE && (ep->attribute & ATTR_DIRECTORY)))
  {
    eunlock(dp);  // 在类型不匹配时释放父目录项的锁
    eput(ep);     // 释放创建的目录项内存
    eput(dp);     // 释放父目录项内存
    return NULL;  // 类型不匹配时返回 NULL
  }

  eunlock(dp);  // 在创建成功后释放父目录项的锁
  eput(dp);     // 释放父目录项内存

  elock(ep);    // 锁定新创建的目录项
  return ep;    // 返回新创建的目录项指针
}

static struct dirent *
create2(char *path, short type, int mode, struct file *f)
{
  struct dirent *ep, *dp;
  char name[FAT32_MAX_FILENAME + 1];

  if ((dp = enameparent2(path, name, f)) == NULL)
  {
    printf("can't find dir\n");
    return NULL;
  }
  if (type == T_DIR)
  {
    mode = ATTR_DIRECTORY;
  }
  else if (mode & O_RDONLY)
  {
    mode = ATTR_READ_ONLY;
  }
  else
  {
    mode = 0;
  }

  elock(dp);
  if ((ep = ealloc(dp, name, mode)) == NULL)
  {
    eunlock(dp);
    eput(dp);
    return NULL;
  }

  if ((type == T_DIR && !(ep->attribute & ATTR_DIRECTORY)) ||
      (type == T_FILE && (ep->attribute & ATTR_DIRECTORY)))
  {
    eunlock(dp);
    eput(ep);
    eput(dp);
    return NULL;
  }

  eunlock(dp);
  eput(dp);

  elock(ep);
  return ep;
}

