  if (!(ep->attribute & ATTR_DIRECTORY) && (omode & O_TRUNC))
  {
    etrunc(ep);
  }

  // 设置文件类型为 FD_ENTRY，设置文件偏移量，指向目录项，设置可读性和可写性
  f->type = FD_ENTRY;
  f->off = (omode & O_APPEND) ? ep->file_size : 0;
  f->ep = ep;
  f->readable = !(omode & O_WRONLY);
  f->writable = (omode & O_WRONLY) || (omode & O_RDWR);

  eunlock(ep);  // 释放目录项的锁

  return fd;  // 返回文件描述符
}

