  __sync_synchronize();

  // 释放锁，相当于 lk->locked = 0。
  // 这段代码不使用 C 语言的赋值，因为 C 标准
  // 暗示赋值可能用多个存储指令实现。
  // 在 RISC-V 上，sync_lock_release 变成一个原子交换：
  //   s1 = &lk->locked
  //   amoswap.w zero, zero, (s1)
  __sync_lock_release(&lk->locked);

  pop_off();
}

// 检查当前 CPU 是否持有锁。
// 必须关闭中断。
int holding(struct spinlock *lk)
{
  int r;
  r = (lk->locked && lk->cpu == mycpu());
  return r;
}

