#include "include/vm.h"

int
pipealloc(struct file **f0, struct file **f1)
{
  struct pipe *pi;

  pi = 0;
  *f0 = *f1 = 0;
  if((*f0 = filealloc()) == NULL || (*f1 = filealloc()) == NULL)
    goto bad;
  if((pi = (struct pipe*)kalloc()) == NULL)
    goto bad;
  pi->readopen = 1;
  pi->writeopen = 1;
  pi->nwrite = 0;
  pi->nread = 0;
  initlock(&pi->lock, "pipe");
  (*f0)->type = FD_PIPE;
  (*f0)->readable = 1;
  (*f0)->writable = 0;
  (*f0)->pipe = pi;
  (*f1)->type = FD_PIPE;
  (*f1)->readable = 0;
  (*f1)->writable = 1;
  (*f1)->pipe = pi;
  return 0;

 bad:
  if(pi)
    kfree((char*)pi);
  if(*f0)
    fileclose(*f0);
  if(*f1)
    fileclose(*f1);
  return -1;
}

void
pipeclose(struct pipe *pi, int writable)
{
  acquire(&pi->lock);
  if(writable){
    pi->writeopen = 0;
    wakeup(&pi->nread);
  } else {
    pi->readopen = 0;
    wakeup(&pi->nwrite);
  }
  if(pi->readopen == 0 && pi->writeopen == 0){
    release(&pi->lock);
    kfree((char*)pi);
  } else
    release(&pi->lock);
}

int
pipewrite(struct pipe *pi, uint64 addr, int n)
{
  int i;
  char ch;
  struct proc *pr = myproc();

  acquire(&pi->lock);
  for(i = 0; i < n; i++){
    while(pi->nwrite == pi->nread + PIPESIZE){  //DOC: pipewrite-full
      if(pi->readopen == 0 || pr->killed){
        release(&pi->lock);
        return -1;
      }
      wakeup(&pi->nread);
      sleep(&pi->nwrite, &pi->lock);
    }
    // if(copyin(pr->pagetable, &ch, addr + i, 1) == -1)
    if(copyin2(&ch, addr + i, 1) == -1)
      break;
    pi->data[pi->nwrite++ % PIPESIZE] = ch;
  }
  wakeup(&pi->nread);
  release(&pi->lock);
  return i;
}

int
piperead(struct pipe *pi, uint64 addr, int n)
{
  int i;
  struct proc *pr = myproc();
  char ch;

  acquire(&pi->lock);
  while(pi->nread == pi->nwrite && pi->writeopen){  //DOC: pipe-empty
    if(pr->killed){
      release(&pi->lock);
      return -1;
    }
    sleep(&pi->nread, &pi->lock); //DOC: piperead-sleep
  }
  for(i = 0; i < n; i++){  //DOC: piperead-copy
    if(pi->nread == pi->nwrite)
      break;
    ch = pi->data[pi->nread++ % PIPESIZE];
    // if(copyout(pr->pagetable, addr + i, &ch, 1) == -1)
    if(copyout2(addr + i, &ch, 1) == -1)
      break;
  }
  wakeup(&pi->nwrite);  //DOC: piperead-wakeup
  release(&pi->lock);
  return i;
}

// Timer Interrupt handler


#include "include/types.h"
#include "include/param.h"
#include "include/riscv.h"
#include "include/sbi.h"
#include "include/spinlock.h"
#include "include/timer.h"
#include "include/printf.h"
#include "include/proc.h"

struct spinlock tickslock;
uint ticks;

struct sleep_proc sleep_procs[N_SLEEP_PRCO];

// 进程睡眠
int gain_sleep(TimeVal *tv){
    struct sleep_proc* sp;
    for(sp=sleep_procs;sp<&sleep_procs[N_SLEEP_PRCO];++sp)
    { // 遍历 sleep_procs 数组，找到一个空闲的 sleep_proc 结构体。
        acquire(&sp->lock);
        if(sp->p==0)
        { // 置其 sleep_ticks 为当前 ticks 加上计算后的睡眠时间。
            sp->p=myproc();
            sp->sleep_ticks=ticks + tv->sec*CLK_FREQ/INTERVAL + tv->usec*(CLK_FREQ/100000)/10/INTERVAL;
            release(&sp->lock);
            return 1;
        }
        release(&sp->lock);
    }
    return 0;
}

//定时器初始化 (timerinit)
//初始化一个全局锁 tickslock，用于保护 ticks 变量。
//初始化 sleep_procs 数组中每个 sleep_proc 结构体的锁，并将其进程指针设置为 0（表示未使用）。
void timerinit() {
    initlock(&tickslock, "time");
    #ifdef DEBUG
    printf("timerinit\n");
    #endif

    struct sleep_proc* sp;

    for(sp=sleep_procs;sp<&sleep_procs[N_SLEEP_PRCO];++sp){
        initlock(&sp->lock,"sleep");
        sp->p=0;
    }
}

// 设置下一个超时 (set_next_timeout)
//使用 SBI（Supervisor Binary Interface）调用 sbi_set_timer 来设置下一个定时器中断的触发时间。
void set_next_timeout()
{
    // There is a very strange bug,
    // if comment the `printf` line below
    // the timer will not work.

    // this bug seems to disappear automatically
    // printf("");
    sbi_set_timer(r_time() + INTERVAL);
}

// 唤醒进程 在定时器中断发生时，wakeup_sleep 函数会被调用
void wakeup_sleep(){
    struct sleep_proc* sp;
    for(sp=sleep_procs;sp<&sleep_procs[N_SLEEP_PRCO];++sp)
    { // 遍历 sleep_procs 数组，检查每个 sleep_proc 结构体
        acquire(&sp->lock);
        if(sp->p!=0){
            if(sp->p->killed){
                sp->p=0;
            }
            else{
                if(ticks>sp->sleep_ticks)
                { // 如果发现有进程需要唤醒且 ticks 达到或超过 sleep_ticks，则将该进程的状态设置为 RUNNABLE。
                    struct proc* p=sp->p;
                    acquire(&p->lock);
                    if(sp->p->state==SLEEPING){
                        sp->p->state=RUNNABLE;
                        sp->p=0;
                    }
                    release(&p->lock);
                }
            }
        }
        release(&sp->lock);
    }
}

// 处理定时器中断
void timer_tick(int cpl) {
    struct proc* p=myproc();
    if(p!=0){
        if(cpl==1)
        { // 根据当前特权级 cpl（current privilege level）更新进程的用户时间或系统时间。
            ++p->ti.tms_stime;
        }
        else{
            ++p->ti.tms_utime;
        }
    }
    acquire(&tickslock);
    ticks++; // 增加 ticks 计数器
    wakeup_sleep(); // 调用 wakeup_sleep 函数，检查是否有进程需要从睡眠中唤醒。
    release(&tickslock);
    set_next_timeout();  // 调用 set_next_timeout 函数，设置下一个定时器中断。
}

