  initlock(&ftable.lock, "ftable");
  struct file *f;
  for(f = ftable.file; f < ftable.file + NFILE; f++){  
    memset(f, 0, sizeof(struct file));
  }
  #ifdef DEBUG
  printf("fileinit\n");
  #endif
}

// Allocate a file structure.
// 在文件表中分配一个文件
struct file*
filealloc(void)   
{
  struct file *f;

  acquire(&ftable.lock);
  for(f = ftable.file; f < ftable.file + NFILE; f++){
    if(f->ref == 0){
      f->ref = 1;
      release(&ftable.lock);
      return f;
    }
  }
  release(&ftable.lock);
  return NULL;
}

// Increment ref count for file f.
// 文件的引用数加一，但必须是已经分配的文件，即该文件的引用数>0
struct file*
filedup(struct file *f)   
{
  acquire(&ftable.lock);
  if(f->ref < 1)
    panic("filedup");
  f->ref++;
  release(&ftable.lock);
  return f;
}

// Close file f.  (Decrement ref count, close when reaches 0.)
// 减少一个文件引用，如果文件的引用变为0，将该文件的类型设为空，如果该文件的文件类型为管道则关闭管道，如果该文件类型为entry，则执行eput
void
fileclose(struct file *f)
{
  struct file ff;  // 新建一个 file 结构体 ff，用于保存要关闭的文件信息

  acquire(&ftable.lock);  // 获取文件表的锁，确保在修改文件表时不会出现并发问题
  if(f->ref < 1)  // 如果文件的引用计数小于1，表示出现了异常情况
    panic("fileclose");  // 触发内核恐慌，终止程序执行
  if(--f->ref > 0){  // 如果减少引用计数之后仍然大于0，表示仍有其他引用此文件的地方
    release(&ftable.lock);  // 释放文件表的锁
    return;  // 提前返回，不执行关闭文件的操作
  }
  ff = *f;  // 将要关闭的文件信息拷贝到新建的 ff 结构体中
  f->ref = 0;  // 将原文件的引用计数置为0，表示文件已不再被引用
  f->type = FD_NONE;  // 将原文件类型标记为FD_NONE，表示文件类型未知
  release(&ftable.lock);  // 释放文件表的锁，关闭临界区

  if(ff.type == FD_PIPE){  // 如果文件类型是管道
    pipeclose(ff.pipe, ff.writable);  // 调用 pipeclose 函数关闭管道
  } else if(ff.type == FD_ENTRY){  // 如果文件类型是目录项
    eput(ff.ep);  // 调用 eput 函数释放目录项
  } else if (ff.type == FD_DEVICE) {  // 如果文件类型是设备文件
            //暂时没写设备
  }
}

// Get metadata about file f.
// addr is a user virtual address, pointing to a struct stat.
//将f的元信息复制到addr处，包括文件名、所属设备、文件类型（目录/文件）、文件大小
int
filestat(struct file *f, uint64 addr)
{
  // struct proc *p = myproc();
  struct stat st;

  if(f->type == FD_ENTRY){
    elock(f->ep);
    estat(f->ep, &st);
    eunlock(f->ep);
    // if(copyout(p->pagetable, addr, (char *)&st, sizeof(st)) < 0)
    if(copyout2(addr, (char *)&st, sizeof(st)) < 0)
      return -1;
    return 0;
  }
  return -1;
}
// 读文件
// 根据文件的类型执行对应的读操作
// Read from file f.
// addr is a user virtual address.
int
fileread(struct file *f, uint64 addr, int n)
{
  int r = 0;

  if(f->readable == 0)
    return -1;

  switch (f->type) {
    case FD_PIPE:
        r = piperead(f->pipe, addr, n);
        break;
    case FD_DEVICE:
        if(f->major < 0 || f->major >= NDEV || !devsw[f->major].read)
          return -1;
        r = devsw[f->major].read(1, addr, n);  // 根据main()中对控制台的初始化可知 console 是一个dev
        break;
    case FD_ENTRY:
        elock(f->ep);
          if((r = eread(f->ep, 1, addr, f->off, n)) > 0)
            f->off += r;
        eunlock(f->ep);
        break;
    default:
      panic("fileread");
  }

  return r;
}
// 写文件
// 根据文件的类型执行对应的读操作
// Write to file f.
// addr is a user virtual address.
int
filewrite(struct file *f, uint64 addr, int n)
{
  int ret = 0;

  if(f->writable == 0)
    return -1;

  if(f->type == FD_PIPE){
    ret = pipewrite(f->pipe, addr, n);
  } else if(f->type == FD_DEVICE){
    if(f->major < 0 || f->major >= NDEV || !devsw[f->major].write)
      return -1;
    ret = devsw[f->major].write(1, addr, n);
  } else if(f->type == FD_ENTRY){
    elock(f->ep);
    if (ewrite(f->ep, 1, addr, f->off, n) == n) {
      ret = n;
      f->off += n;
    } else {
      ret = -1;
    }
    eunlock(f->ep);
  } else {
    panic("filewrite");
  }

  return ret;
}

// Read from dir f.
// addr is a user virtual address.
// 找到下一个目录
int
dirnext(struct file *f, uint64 addr)
{
  // struct proc *p = myproc();

  if(f->readable == 0 || !(f->ep->attribute & ATTR_DIRECTORY)) // 如果不是目录就返回-1  
    return -1;

  struct dirent de;
  struct stat st;
  int count = 0;
  int ret;
  elock(f->ep);
  while ((ret = enext(f->ep, &de, f->off, &count)) == 0) {  // skip empty entry
    f->off += count * 32;
  }
  eunlock(f->ep);
  if (ret == -1)
    return 0;

  f->off += count * 32;
  estat(&de, &st);
  // if(copyout(p->pagetable, addr, (char *)&st, sizeof(st)) < 0)
  if(copyout2(addr, (char *)&st, sizeof(st)) < 0)
    return -1;

  return 1;
}

