uint64 do_mmap(uint64 start, long len, int prot, int flags, int fd, long off)
{
  uint64 start_address = start;
  struct proc *p = myproc();
  uint64 old = p->sz;

  if (start == 0)
  {
    start_address = alloc_v_space(len); // 如果start为0，系统分配一个合适大小的虚拟地址
  }

  if (p->mfile.valid == 1)
  { // 每个进程只能映射一个文件，当请求第二个时返回错误
    return -1;
  }
  else
  {
    p->mfile.valid = 1;
  }

  if (start_address + (int)len > TRAPFRAME)
  { // 判断是否越界
    printf("1\n");
    return -1;
  }

  if (start_address < old)
  { // 判断是否越界
    printf("2\n");
    return -1;
  }

  struct file *file = p->ofile[fd];
  if (file == 0)
  {
    printf("3\n");
    return -1;
  }

  if (off > file->ep->file_size)
  { // 判断是否越界
    printf("4\n");
    return -1;
  }

  acquire(&file->lock); // 对file结构体的操作需要锁（原来并没有锁，为了满足原子操作新加的）

  if (flags & MAP_SHARED)
  { // 对flag的判断
    if (file->map_pid < 0)
    {
      file->map_pid = 0;
    }
    else if (file->map_pid > 0)
    {
      printf("it has been privately shared!\n");
      return -1;
    }
  }
  else if (flags & MAP_PRIVATE)
  {
    if (file->map_pid < 0)
    {
      file->map_pid = p->pid;
    }
    else if (file->map_pid > 0)
    {
      printf("it has been privately shared!\n");
      return -1;
    }
  }
  else
  {
    return -1;
  }

  release(&file->lock);

  if (start_map(start_address, len, prot, file->ep, off) == -1)
  { // 开始映射
    panic("map error\n");
    return -1;
  }

  p->mfile.baseaddr = start_address;
  p->mfile.len = PGROUNDUP(len);
  p->mfile.mfile = file;
  p->mfile.off = off;
  return start_address;
}

// 取消内存映射
uint64 do_munmap(uint64 start, long len)
{
  if ((start % PGSIZE) != 0)
  {
    panic("in do_munmap :start must be page aligned");
  }

  struct proc *p = myproc();

  if (p->mfile.valid != 1)
  {
    printf("-3\n");
    return -1;
  }

  if (start < p->mfile.baseaddr || start > p->mfile.baseaddr + p->mfile.len)
  {
    printf("-1\n");
    return -1;
  }

  if (start + (int)len > p->mfile.baseaddr + p->mfile.len)
  {
    len = p->mfile.len;
  }

  if (!syn_disk(start, len))
  {
    printf("-2\n");
    end_map(start, len);
    return -1;
  }

  end_map(start, len); // 取消映射

  acquire(&p->lock);
  p->sz = PGROUNDUP(p->sz) - PGROUNDUP(len);
  release(&p->lock);

  p->mfile.valid = 0;
  return 0;
}

