// 调用者必须持有 p->lock。
void reparent(struct proc *p)
{
  struct proc *pp;

  // 遍历所有进程，寻找 p 的子进程
  // for (pp = proc; pp < &proc[NPROC]; pp++)
  for (pp = proc_freelist; pp != NULL; pp = pp->next)
  {
    // 在不持有 pp->lock 的情况下使用 pp->parent，先获取锁可能会导致死锁
    // 如果 pp 或 pp 的子进程也处于 exit() 中即将尝试锁定 p 的情况
    if (pp->parent == p)
    {
      // pp->parent 在检查和获取锁之间不能改变，
      // 因为只有父进程可以改变它，而我们就是父进程。
      acquire(&pp->lock);
      pp->parent = initproc;
      // 此处应唤醒 init 进程，但这将需要 initproc->lock，
      // 这会导致死锁，因为我们持有 init 的子进程（pp）的锁。
      // 这就是为什么 exit() 总是在获取任何锁之前唤醒 init。
      release(&pp->lock);
    }
  }
}

// 退出当前进程，不返回。
// 一个退出的进程会一直处于僵尸状态，直到其父进程调用 wait()。
void exit(int status)
{
  struct proc *p = myproc();

  if (p == initproc)
  {
    panic("init exiting");
  }

  // 关闭所有打开的文件。
  for (int fd = 0; fd < NOFILE; fd++)
  {
    if (p->ofile[fd])
    {
      struct file *f = p->ofile[fd];
      fileclose(f);
      p->ofile[fd] = 0;
    }
  }

  eput(p->cwd);
  p->cwd = 0;

  // 可能我们将子进程交给了 init。我们无法确定地唤醒 init，
  // 因为一旦我们获取了其他进程的锁，就无法获取 init 的锁了。
  // 所以不管有没有必要，都唤醒 init。init 可能会错过这个唤醒，但这似乎是无害的。
  acquire(&initproc->lock);
  wakeup1(initproc);
  release(&initproc->lock);

  // 获取 p->parent 的一个副本，以确保我们解锁的是同一个父进程。
  // 如果我们的父进程在等待父进程锁的同时把我们交给了 init。
  // 那么我们可能会与一个正在退出的父进程竞争，但结果将是对一个已死亡或错误进程的无害的虚假唤醒；
  // proc 结构永远不会被重新分配为其他内容。
  acquire(&p->lock);
  struct proc *original_parent = p->parent;
  release(&p->lock);

  // 为了从 wait() 中唤醒父进程，我们需要父进程的锁。
  // 先锁定父进程是因为父进程-子进程规则说我们必须先锁定父进程。
  acquire(&original_parent->lock);

  acquire(&p->lock);

  // 将任何子进程交给 init 进程。
  reparent(p);

  // 父进程可能正在 wait() 中休眠。
  wakeup1(original_parent);

  p->xstate = status;
  p->state = ZOMBIE;

  release(&original_parent->lock);

  // 跳入调度程序，永不返回。
  sched();
  panic("zombie exit");
}

