// 每个 CPU 在设置完自身后调用 scheduler()。
// 调度器永不返回。它循环执行以下操作：
//  - 选择一个要运行的进程。
//  - 使用 swtch 切换到开始运行该进程。
//  - 最终，该进程通过 swtch 将控制权转交回调度器。
void scheduler(void)
{
  //struct proc *np;
  struct proc *p;                      // 声明一个指向 struct proc 结构的指针，用于遍历所有进程
  struct cpu *c = mycpu();             // 获取当前 CPU 的结构体指针，用于记录当前正在运行的进程
  extern pagetable_t kernel_pagetable; // 外部引用内核页表

  c->proc = 0; // 将当前运行的进程指针设为 0，表示当前没有进程在运行
  for (;;)
  { // 进入一个无限循环，表示调度器将一直运行
    // 通过确保设备可以中断来避免死锁。
    intr_on(); // 打开中断，确保设备中断能够被触发，以避免死锁

    int found = 0; // 初始化一个变量 found，用于表示是否找到可运行的进程

    //******************************尝试
    // for (p = proc; p < &proc[NPROC]; p++)
    // acquire(&proc_freelist_lock); // 获取进程链表的锁

    for (p = proc_freelist; p != NULL; p = p->next)
    //******************************尝试

    { // 遍历所有进程，从 proc 数组开始，到 proc 数组结束

      acquire(&p->lock); // 获取当前进程的锁，确保只有一个进程能够进入临界区
      if (p->state == RUNNABLE)
      { 

        p->state = RUNNING; // 将当前进程的状态设置为 RUNNING，表示该进程正在运行
        c->proc = p;        // 将当前运行的进程指针设为 p

        w_satp(MAKE_SATP(p->kpagetable)); // 将 satp设置为当前进程的内核页表
        sfence_vma();                     // 执行虚拟内存地址空间刷新操作，确保上下文切换后的页表生效

        swtch(&c->context, &p->context); // 实现上下文切换,这个函数结束后cpu直接开始执行新的进程，保存当前 CPU 的上下文（寄存器状态）到 c->context，恢复要切换进来的进程的上下文（保存在 p->context 中）

        w_satp(MAKE_SATP(kernel_pagetable)); // 将 satp设置为内核页表，恢复原先的内核页表
        sfence_vma();                        // 执行虚拟内存地址空间刷新操作，确保返回到内核时的页表生效
                                             // 进程暂时结束运行，它应该在返回之前改变自己的状态
        c->proc = 0; // 将当前运行的进程指针设为 0，表示当前没有进程在运行

        found = 1; // 将 found 设置为 1，表示找到了一个可运行的进程
      }

      release(&p->lock); // 释放当前进程的锁，允许其他进程进入临界区
    }

    //******************************尝试
    // release(&proc_freelist_lock); // 释放进程链表的锁
    //******************************尝试
    if (found == 0)
    {
      intr_on();           // 打开中断，确保设备中断能够被触发
      asm volatile("wfi"); // 执行等待中断指令 wfi，暂停 CPU 的执行，直到发生中断为止。这样可以降低 CPU 的功耗并释放 CPU 的资源
    }
  }
}

// 切换到调度器。必须只持有p->lock，
// 并且已经改变了proc->state。保存并恢复
// intena，因为intena是这个内核线程的属性，而不是这个 CPU 的属性。应该
// 是 proc->intena 和 proc->noff，但这样会破坏一个锁被持有但
// 没有进程的少数情况。
void sched(void)
{

  int intena;
  struct proc *p = myproc();

  if (!holding(&p->lock)) // 检查当前 CPU 的锁数量是否为 1，如果不是，则触发 panic。这是为了确保在调度过程中不会发生锁的重入。
    panic("sched p->lock");
  if (mycpu()->noff != 1)
    panic("sched locks");
  if (p->state == RUNNING)
    panic("sched running");
  if (intr_get()) // 检查当前是否处于可中断的状态，如果是，则触发 panic。这是为了确保在调度过程中不会被中断。
    panic("sched interruptible");

  // printf("我要切换回来进程执行流了进程名为 %s 所在的cpu为 %d ...\n", p->name, cpuid());
  intena = mycpu()->intena;
  swtch(&p->context, &mycpu()->context); // 当前进程调用 sched 函数，其中 swtch(&p->context, &mycpu()->context) 保存了当前进程的上下文并切换到 CPU 的上下文。注意这个切换不是直接两个进程之间切换，而是进程切换到cpu调度器执行流，然后在从调度器执行流切换到另一个进程
  mycpu()->intena = intena;
}

// 放弃 CPU 一个调度回合。
void yield(void)
{
  struct proc *p = myproc();

  acquire(&p->lock);
  p->state = RUNNABLE;
  sched();
  release(&p->lock);
}

